#include <bits/stdc++.h>
using namespace std;

const int N = 100005;

vector<int> g[N];
int deg[N];
int layer[N];
int n, k;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n >> k;
    for(int i = 1; i <= n; i++){
        g[i].clear();
        deg[i] = 0;
        layer[i] = -1;
    }

    for(int i = 1; i < n; i++){
        int u, v;
        cin >> u >> v;
        g[u].push_back(v);
        g[v].push_back(u);
        deg[u]++;
        deg[v]++;
    }

    queue<int> q;

    // 初始叶子
    for(int i = 1; i <= n; i++){
        if(deg[i] <= 1){
            q.push(i);
            layer[i] = 0;
        }
    }

    int maxLayer = 0;

    // 拓扑删叶子
    while(!q.empty()){
        int u = q.front(); q.pop();
        for(int v : g[u]){
            if(layer[v] != -1) continue;
            deg[v]--;
            if(deg[v] == 1){
                layer[v] = layer[u] + 1;
                maxLayer = max(maxLayer, layer[v]);
                q.push(v);
            }
        }
    }

    vector<int> cnt(maxLayer + 1, 0);
    for(int i = 1; i <= n; i++){
        cnt[layer[i]]++;
    }

    int remain = n;
    for(int R = 0; R <= maxLayer; R++){
        remain -= cnt[R];
        if(remain <= k){
            cout << R << "\n";
            break;
        }
    }

    return 0;
}
